def approximate_vertex_cover(edges):
    vc = set()

    current_edges = {frozenset(edge) for edge in edges}

    while current_edges:
        chosen_edge = current_edges.pop()

        u, v = tuple(chosen_edge)

        vc.add(u)
        vc.add(v)

        edges_to_remove_in_this_step = set()
        for edge in current_edges:
            if u in edge or v in edge:
                edges_to_remove_in_this_step.add(edge)

        current_edges = current_edges - edges_to_remove_in_this_step

    return vc
